// Headless test for src/shared/accounts/ratings/detmath.ts (phase A4 brick
// 1a — deterministic exp/ln for the ratings folds).
//
//   node scripts/test-accounts-detmath.mjs
//
// Bundles the TS module on the fly with esbuild (alias @shared → src/shared,
// same pattern as scripts/test-accounts-chain.mjs) and drives:
//  (a) 89 golden vectors asserting EXACT float64 bit patterns (DataView
//      getBigUint64) — generated by the implementation once at build time and
//      FROZEN; their job is catching future drift and cross-engine
//      divergence, so never regenerate them casually,
//  (b) relative-error bounds vs Math.exp/Math.log over dense grids (budget
//      ≤ 1e-12 per the brief; measured < 3e-16 at build time),
//  (c) monotonicity — full-grid scans plus spot pairs straddling the
//      argument-reduction boundaries (k=0↔±1 for dexp, √2 edges for dln),
//  (d) round-trips dexp(dln(x)) ≈ x and dln(dexp(x)) ≈ x,
//  (e) the special-value rules documented in the module header
//      (NaN/±Inf propagation, overflow→+∞, graceful underflow→+0),
// plus a same-process double-evaluation bit-identity scan.
//
// Style: failures counter, per-assert one-line output, exit(failures ? 1 : 0).

import { build } from 'esbuild'
import { pathToFileURL, fileURLToPath } from 'node:url'
import { dirname, resolve } from 'node:path'
import { mkdtempSync, rmSync, mkdirSync, writeFileSync } from 'node:fs'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = resolve(__dirname, '..')
const SRC = resolve(ROOT, 'src/shared/accounts').replace(/\\/g, '/')

// ---- tiny check kit ---------------------------------------------------------
let passed = 0
let failures = 0
function ok(cond, msg) {
  if (cond) {
    passed++
    console.log(`  ✓ ${msg}`)
  } else {
    failures++
    console.log(`  ✗ ${msg}`)
  }
}
function eq(a, b, msg) {
  ok(a === b, a === b ? msg : `${msg} (got ${JSON.stringify(a)}, want ${JSON.stringify(b)})`)
}

// ---- float64 bit access -----------------------------------------------------
const dv = new DataView(new ArrayBuffer(8))
/** Exact big-endian float64 bit pattern as 16 lowercase hex chars. */
function bitsOf(v) {
  dv.setFloat64(0, v)
  return dv.getBigUint64(0).toString(16).padStart(16, '0')
}
const relErr = (got, want) => (got === want ? 0 : Math.abs(got - want) / Math.abs(want))

// ---- golden vectors (FROZEN from the first green build — determinism ------
// ---- anchors; any drift on any engine breaks these at once) ----------------
// [input (exact shortest-round-trip literal), expected float64 bits (hex)]
const GOLDEN_EXP = [
  [0, '3ff0000000000000'],
  [3.725290298461914e-9, '3ff0000001000000'], // exactly 2^-28: first input past the 1+x shortcut
  [-3.725290298461914e-9, '3feffffffe000000'],
  [1e-10, '3ff000000006df38'], // inside the 1+x shortcut
  [-1e-10, '3feffffffff24190'],
  [0.25, '3ff48b5e3c3e8186'],
  [-0.25, '3fe8ebef9eac820b'],
  [0.34657359027997264, '3ff6a09e667f3bcc'], // ~ln2/2: k=0↔1 reduction edge
  [-0.34657359027997264, '3fe6a09e667f3bcc'],
  [0.3465735902799727, '3ff6a09e667f3bcd'], // just across the edge
  [-0.3465735902799727, '3fe6a09e667f3bcc'],
  [0.5, '3ffa61298e1e069c'],
  [-0.5, '3fe368b2fc6f960a'],
  [1, '4005bf0a8b14576a'], // e
  [-1, '3fd78b56362cef38'],
  [0.6931471805599453, '4000000000000000'], // ln2 → exactly 2
  [-0.6931471805599453, '3fe0000000000000'], // → exactly 0.5
  [1.0397207708399179, '4006a09e667f3bcc'], // 1.5·ln2: k=1↔2 edge
  [-1.0397207708399179, '3fd6a09e667f3bcd'],
  [2, '401d8e64b8d4ddae'],
  [-2, '3fc152aaa3bf81cc'],
  [2.718281828459045, '402e4efb75e4527a'], // e^e
  [-2.718281828459045, '3fb0e49787e20548'],
  [3.141592653589793, '403724046eb09339'], // e^π
  [3.5, '40408ec721396bdb'],
  [-3.5, '3f9eec1018e4ff66'],
  [6.931471805599453, '4090000000000000'], // 10·ln2 → exactly 1024
  [-6.931471805599453, '3f50000000000000'], // → exactly 2^-10
  [5.626821433520073, '40715c71c71c71c7'], // −ln(vol²) at seed vol 0.06 (Glicko Illinois loop)
  [-5.626821433520073, '3f6d7dbf487fcb92'], // a = ln(0.06²)
  [-2.8134107167600364, '3faeb851eb851eb8'], // a/2 → exactly 0.06 (seed vol round-trip)
  [-11.253642867040146, '3eeb2dd8d6457178'], // 2a — deep volatility bracket
  [10, '40d5829dcf950560'],
  [-10, '3f07cd79b5647c9a'],
  [25, '4230c3d3920962c9'],
  [-25, '3dae8a37a45fc32e'],
  [40, '438a220d397972ea'], // brief's |x| ≤ ~40 Glicko rim
  [-40, '3c539792499b1a24'],
  [50, '44719103e4080b45'], // required |x| ≤ 50 rim
  [-50, '3b6d257d547e083f'],
  [100, '48f3494a9b171bf5'],
  [-100, '36ea8c1f14e2af5d'],
  [350.5, '5f895cbd90b53414'],
  [-350.5, '20542ffdfebeef96'],
  [700, '7f0d945df4f8ec8e'],
  [-700, '00d14f2b0fb9307f'], // subnormal-adjacent normal result
  [709.782712893384, '7fefffffffffff2a'], // exactly the overflow threshold → near DBL_MAX, finite
  [-709, '0008bfe55de02338'], // subnormal result
  [-740, '0000000000000055'], // deep subnormal
  [-744.5, '0000000000000001'], // smallest subnormal 5e-324
  [-745.1332191019411, '0000000000000001'], // underflow threshold itself (still rounds up to 5e-324)
]
const GOLDEN_LN = [
  [5e-324, 'c0874385446d71c3'], // smallest subnormal
  [1e-300, 'c085963447f87fb5'],
  [2.2250738585072014e-308, 'c086232bdd7abcd2'], // smallest normal
  [1e-12, 'c03ba18a998fffa0'],
  [1e-9, 'c034b927f32bffb8'],
  [0.000001, 'c02ba18a998fffa0'],
  [0.0036, 'c01681dd7a559a2a'], // Glicko seed vol² (Illinois a = ln(vol²))
  [0.06, 'c00681dd7a559a2a'], // Glicko seed vol
  [0.1, 'c0026bb1bbb55515'],
  [0.25, 'bff62e42fefa39ef'], // −2·ln2
  [0.5, 'bfe62e42fefa39ef'], // −ln2
  [0.7071067811865475, 'bfd62e42fefa39f1'], // just below the √2/2 normalization edge
  [0.7071067811865476, 'bfd62e42fefa39ee'], // the edge (k=0 side)
  [0.9, 'bfbaf8e8210a415c'],
  [0.99999999999, 'bda5fd80000078e5'], // f→0 cancellation zone
  [1, '0000000000000000'], // exactly +0
  [1.00000000001, '3da5fd7fffff871b'],
  [1.1, '3fb8663f793c46cc'],
  [1.414213562373095, '3fd62e42fefa39ee'], // just below the √2 edge (k=0 side)
  [1.4142135623730951, '3fd62e42fefa39f0'], // the edge (k=1 side)
  [1.4142135623730954, '3fd62e42fefa39f3'],
  [2, '3fe62e42fefa39ef'], // ln2
  [2.718281828459045, '3ff0000000000000'], // ln(e) → exactly 1
  [3, '3ff193ea7aad030a'],
  [7, '3fff2272ae325a57'],
  [10, '40026bb1bbb55516'],
  [100, '40126bb1bbb55516'],
  [173.7178, '4014a135e44f30c9'], // Glicko SCALE
  [1200, '401c5c3d1a1f2454'], // seed rating
  [1500, '401d40bcd85bf925'], // Glicko-2 center
  [2.014761872416068, '3fe66a81189b9d24'], // seed RD 350 / SCALE
  [10000, '40226bb1bbb55516'],
  [123456.789, '40277281cad8a844'],
  [1000000, '402ba18a998fffa0'],
  [1000000000, '4034b927f32bffb8'],
  [1000000000000, '403ba18a998fffa0'], // required domain rim 1e12
  [9007199254740992, '40425e4f7b2737fa'], // 2^53 — beyond-domain sanity
  [1e+300, '4085963447f87fb5'],
]

async function main() {
  const cacheRoot = resolve(ROOT, 'node_modules/.cache/accounts-detmath-test')
  mkdirSync(cacheRoot, { recursive: true })
  const outdir = mkdtempSync(resolve(cacheRoot, 'run-'))
  try {
    await run(outdir)
  } finally {
    rmSync(outdir, { recursive: true, force: true })
  }
  console.log(`\n${failures ? `❌ ${failures} FAILED — ` : 'ALL GREEN — '}${passed} assertions${failures ? `, ${failures} failures` : ''}`)
  process.exit(failures ? 1 : 0)
}

async function run(outdir) {
  // ---- bundle ---------------------------------------------------------------
  console.log('· bundling src/shared/accounts/ratings/detmath …')
  const entry = resolve(outdir, 'entry.ts')
  writeFileSync(entry, `export * from '${SRC}/ratings/detmath.ts'`)
  const outfile = resolve(outdir, 'detmath.mjs')
  await build({
    entryPoints: [entry],
    outfile,
    bundle: true,
    format: 'esm',
    platform: 'node',
    mainFields: ['module', 'main'],
    conditions: ['import', 'module', 'default'],
    alias: { '@shared': resolve(ROOT, 'src/shared') },
    absWorkingDir: ROOT,
    logLevel: 'warning',
  })
  const { dexp, dln } = await import(pathToFileURL(outfile).href)

  // ---- (a) golden vectors: exact bit patterns -------------------------------
  console.log('\n— golden vectors (exact float64 bits) —')
  for (const [x, want] of GOLDEN_EXP) eq(bitsOf(dexp(x)), want, `dexp(${x}) bits`)
  for (const [x, want] of GOLDEN_LN) eq(bitsOf(dln(x)), want, `dln(${x}) bits`)

  // ---- (b) relative-error bounds vs Math.* ----------------------------------
  console.log('\n— relative error vs Math.exp / Math.log (budget 1e-12) —')
  {
    // dexp over the Glicko range [-50, 50], 16001 points in 8 chunks.
    const N = 16000
    let overallMax = 0
    for (let c = 0; c < 8; c++) {
      let max = 0
      for (let i = c * (N / 8); i <= (c + 1) * (N / 8); i++) {
        const x = -50 + i * (100 / N)
        const e = relErr(dexp(x), Math.exp(x))
        if (e > max) max = e
      }
      if (max > overallMax) overallMax = max
      ok(max <= 1e-12, `dexp relerr ≤ 1e-12 on [${(-50 + c * 12.5).toFixed(1)}, ${(-37.5 + c * 12.5).toFixed(1)}] (max ${max.toExponential(2)})`)
    }
    console.log(`  · measured max dexp relerr on [-50,50]: ${overallMax.toExponential(3)}`)
  }
  {
    // dexp over the full normal-result range (coarse).
    let max = 0
    for (let i = 0; i <= 4000; i++) {
      const x = -708 + i * ((709.7 + 708) / 4000)
      const e = relErr(dexp(x), Math.exp(x))
      if (e > max) max = e
    }
    ok(max <= 1e-12, `dexp relerr ≤ 1e-12 on [-708, 709.7] (max ${max.toExponential(2)})`)
  }
  {
    // dln over the required domain (0, 1e12], log-spaced, 8 chunks; the grid
    // extends below to 1e-12 (safety margin) and dodges nothing.
    const N = 16000
    let overallMax = 0
    for (let c = 0; c < 8; c++) {
      let max = 0
      for (let i = c * (N / 8); i <= (c + 1) * (N / 8); i++) {
        const x = 1e-12 * Math.pow(10, 24 * (i / N))
        const e = x === 1 ? 0 : relErr(dln(x), Math.log(x))
        if (e > max) max = e
      }
      if (max > overallMax) overallMax = max
      ok(max <= 1e-12, `dln relerr ≤ 1e-12 on decades [1e${-12 + c * 3}, 1e${-9 + c * 3}] (max ${max.toExponential(2)})`)
    }
    console.log(`  · measured max dln relerr on (1e-12, 1e12]: ${overallMax.toExponential(3)}`)
  }
  {
    // dln dense near 1 (cancellation zone).
    let max = 0
    for (let i = 0; i <= 4000; i++) {
      const x = 0.9 + i * (0.2 / 4000)
      if (x === 1) continue
      const e = relErr(dln(x), Math.log(x))
      if (e > max) max = e
    }
    ok(max <= 1e-12, `dln relerr ≤ 1e-12 on [0.9, 1.1] dense (max ${max.toExponential(2)})`)
  }

  // ---- (c) monotonicity -----------------------------------------------------
  console.log('\n— monotonicity —')
  {
    let strict = true
    let prev = dexp(-50)
    for (let i = 1; i <= 8000; i++) {
      const y = dexp(-50 + i * (100 / 8000))
      if (!(y > prev)) strict = false
      prev = y
    }
    ok(strict, 'dexp strictly increasing over 8001-point grid on [-50, 50]')
  }
  {
    let strict = true
    let prev = dln(1e-12)
    for (let i = 1; i <= 8000; i++) {
      const y = dln(1e-12 * Math.pow(10, 24 * (i / 8000)))
      if (!(y > prev)) strict = false
      prev = y
    }
    ok(strict, 'dln strictly increasing over 8001-point log grid on [1e-12, 1e12]')
  }
  ok(dexp(0.34657359027997264) < dexp(0.3465735902799727), 'dexp increases across the k=0→1 reduction edge')
  ok(dexp(-0.3465735902799727) <= dexp(-0.34657359027997264), 'dexp non-decreasing across the k=0→−1 reduction edge')
  ok(dexp(1.0397207708399178) < dexp(1.039720770839918), 'dexp increases across the k=1→2 reduction edge')
  ok(dln(1.414213562373095) < dln(1.4142135623730951), 'dln increases across the √2 normalization edge')
  ok(dln(0.7071067811865475) < dln(0.7071067811865476), 'dln increases across the √2/2 normalization edge')
  ok(dexp(-745.2) < dexp(-744.5) && dexp(-744.5) < dexp(-709), 'dexp ordered through the subnormal underflow strip')

  // ---- (d) round-trips ------------------------------------------------------
  console.log('\n— round-trips —')
  {
    let max = 0
    for (let i = 0; i <= 84; i++) {
      const x = 1e-9 * Math.pow(10, 21 * (i / 84)) // (1e-9 .. 1e12]
      const e = relErr(dexp(dln(x)), x)
      if (e > max) max = e
    }
    ok(max <= 1e-12, `dexp(dln(x)) ≈ x over log grid (1e-9, 1e12] (max relerr ${max.toExponential(2)})`)
  }
  {
    let max = 0
    for (let x = 0.5; x <= 50; x += 0.5) {
      const e1 = relErr(dln(dexp(x)), x)
      const e2 = relErr(dln(dexp(-x)), -x)
      if (e1 > max) max = e1
      if (e2 > max) max = e2
    }
    ok(max <= 1e-12, `dln(dexp(±x)) ≈ ±x for 0.5 ≤ x ≤ 50 (max relerr ${max.toExponential(2)})`)
  }
  eq(dln(dexp(0)), 0, 'dln(dexp(0)) === 0 exactly')
  eq(dexp(dln(1)), 1, 'dexp(dln(1)) === 1 exactly')

  // ---- (e) special-value rules (module-header contract) ---------------------
  console.log('\n— special values —')
  ok(Number.isNaN(dexp(NaN)), 'dexp(NaN) → NaN')
  eq(dexp(Infinity), Infinity, 'dexp(+Inf) → +Inf')
  ok(dexp(-Infinity) === 0 && 1 / dexp(-Infinity) === Infinity, 'dexp(−Inf) → +0')
  eq(dexp(0), 1, 'dexp(0) === 1 exactly')
  eq(dexp(709.7827128933841), Infinity, 'dexp just above the overflow threshold → +Inf')
  eq(dexp(710), Infinity, 'dexp(710) → +Inf (overflow)')
  eq(dexp(1000), Infinity, 'dexp(1000) → +Inf (overflow)')
  ok(dexp(-745.14) === 0 && 1 / dexp(-745.14) === Infinity, 'dexp below the underflow threshold → +0')
  ok(dexp(-1000) === 0 && 1 / dexp(-1000) === Infinity, 'dexp(−1000) → +0 (graceful underflow)')
  eq(dexp(-744.5), 5e-324, 'dexp lands on the smallest subnormal before 0')
  ok(Number.isNaN(dln(NaN)), 'dln(NaN) → NaN')
  ok(Number.isNaN(dln(-1)), 'dln(−1) → NaN')
  ok(Number.isNaN(dln(-Infinity)), 'dln(−Inf) → NaN')
  eq(dln(0), -Infinity, 'dln(+0) → −Inf')
  eq(dln(-0), -Infinity, 'dln(−0) → −Inf')
  eq(dln(Infinity), Infinity, 'dln(+Inf) → +Inf')
  ok(dln(1) === 0 && 1 / dln(1) === Infinity, 'dln(1) → +0 exactly')

  // ---- same-process double-evaluation bit identity --------------------------
  console.log('\n— re-evaluation bit identity —')
  {
    let same = true
    for (let i = 0; i <= 1000; i++) {
      const x = -50 + i * 0.1
      if (bitsOf(dexp(x)) !== bitsOf(dexp(x))) same = false
      const p = 1e-12 * Math.pow(10, 24 * (i / 1000))
      if (bitsOf(dln(p)) !== bitsOf(dln(p))) same = false
    }
    ok(same, 'dexp/dln re-evaluation is bit-identical over 1001-point grids')
  }
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})
